using System.Text.Json;
using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/{section}",
        Name = "Config Section",
        MimeType = "application/json"),
     Description("Returns a specific section of the application configuration.")]
    public static string GetConfigSection(
        [Description("Configuration section name (e.g. 'features')")] string section)
    {
        if (AppConfig.TryGetValue(section, out var value))
            return JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true });

        return JsonSerializer.Serialize(new { error = $"Section '{section}' not found" });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Checks whether a specific feature flag is enabled.")]
    public static string CheckFeatureFlag(
        [Description("Name of the feature flag to check")] string flagName)
    {
        var flags = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        };

        return flags.TryGetValue(flagName, out var enabled)
            ? $"Feature '{flagName}' is {(enabled ? "enabled" : "disabled")}."
            : $"Feature '{flagName}' not found.";
    }
}

